class CertificatePinner: NSObject, URLSessionDelegate {
    private let pinnedHashes: Set<String>
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
        self.pinnedHashes = [
            "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",
            "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="
        ]
        super.init()
    }
    
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        if environment.requiresPinning {
            if validatePinning(serverTrust: serverTrust, domain: challenge.protectionSpace.host) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
        } else {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        }
    }
    
    private func validatePinning(serverTrust: SecTrust, domain: String) -> Bool {
        var secResult = SecTrustResultType.invalid
        let status = SecTrustEvaluate(serverTrust, &secResult)
        
        guard status == errSecSuccess else {
            return false
        }
        
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        
        for i in 0..<certificateCount {
            guard let certificate = SecTrustGetCertificateAtIndex(serverTrust, i) else {
                continue
            }
            
            let publicKey = SecCertificateCopyKey(certificate)
            guard let key = publicKey else {
                continue
            }
            
            guard let publicKeyData = SecKeyCopyExternalRepresentation(key, nil) as Data? else {
                continue
            }
            
            let hash = sha256(data: publicKeyData)
            let base64Hash = "sha256/" + hash.base64EncodedString()
            
            if pinnedHashes.contains(base64Hash) {
                return true
            }
        }
        
        return false
    }
    
    private func sha256(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
}

